arguments.file_text:
namespace RecipeShare.Models;

public class Recipe
{
    public int Id { get; set; }
    public string Title { get; set; } = string.Empty;
    public string Category { get; set; } = string.Empty;
    public string Ingredients { get; set; } = string.Empty;
    public string Steps { get; set; } = string.Empty;
    public double AverageRating { get; set; }
    public int RatingCount { get; set; }
}

using RecipeShare.Models;

namespace RecipeShare.Services;

public class RecipeService
{
    private readonly List<Recipe> _recipes;
    // Track all individual ratings per recipe for accurate averages
    private readonly Dictionary<int, List<int>> _ratings = new();

    public RecipeService()
    {
        _recipes = new List<Recipe>
        {
            new()
            {
                Id = 1, Title = "Classic Margherita Pizza", Category = "Italian",
                Ingredients = "Pizza dough\nSan Marzano tomatoes\nFresh mozzarella\nFresh basil\nOlive oil\nSalt",
                Steps = "1. Preheat oven to 475°F (245°C).\n2. Roll out the dough on a floured surface.\n3. Spread crushed tomatoes over the dough.\n4. Tear mozzarella and distribute evenly.\n5. Bake for 10–12 minutes until crust is golden.\n6. Top with fresh basil and a drizzle of olive oil.",
                AverageRating = 4.5, RatingCount = 12
            },
            new()
            {
                Id = 2, Title = "Spaghetti Carbonara", Category = "Italian",
                Ingredients = "Spaghetti\nGuanciale or pancetta\nEgg yolks\nPecorino Romano\nBlack pepper",
                Steps = "1. Cook spaghetti in salted boiling water until al dente.\n2. Crisp the guanciale in a skillet over medium heat.\n3. Whisk egg yolks with grated Pecorino and pepper.\n4. Toss hot pasta with guanciale, remove from heat.\n5. Stir in the egg mixture quickly to create a creamy sauce.\n6. Serve immediately with extra Pecorino.",
                AverageRating = 4.8, RatingCount = 20
            },
            new()
            {
                Id = 3, Title = "Chicken Tikka Masala", Category = "Indian",
                Ingredients = "Chicken breast\nYogurt\nGaram masala\nTurmeric\nCumin\nCanned tomatoes\nHeavy cream\nGarlic\nGinger\nOnion",
                Steps = "1. Marinate chicken in yogurt, garam masala, turmeric, and cumin for 1 hour.\n2. Grill or broil chicken until charred.\n3. Sauté onion, garlic, and ginger in a pot.\n4. Add canned tomatoes and simmer 15 minutes.\n5. Stir in cream and sliced chicken.\n6. Simmer 10 minutes and serve with rice or naan.",
                AverageRating = 4.7, RatingCount = 15
            },
            new()
            {
                Id = 4, Title = "Vegetable Biryani", Category = "Indian",
                Ingredients = "Basmati rice\nMixed vegetables\nOnion\nYogurt\nBiryani masala\nSaffron\nMint leaves\nGhee",
                Steps = "1. Soak basmati rice for 30 minutes, then parboil.\n2. Sauté sliced onions in ghee until golden.\n3. Add vegetables and biryani masala, cook 5 minutes.\n4. Layer rice and vegetable mixture in a heavy pot.\n5. Add saffron milk and mint leaves.\n6. Cover tightly and cook on low heat for 20 minutes.",
                AverageRating = 4.3, RatingCount = 8
            },
            new()
            {
                Id = 5, Title = "Tacos al Pastor", Category = "Mexican",
                Ingredients = "Pork shoulder\nPineapple\nChili peppers\nAchiote paste\nCorn tortillas\nOnion\nCilantro\nLime",
                Steps = "1. Blend chili peppers and achiote paste into a marinade.\n2. Coat pork shoulder and marinate overnight.\n3. Roast pork at 375°F for 2 hours until tender.\n4. Slice pork thinly and sear with pineapple chunks.\n5. Warm corn tortillas.\n6. Assemble tacos with pork, pineapple, onion, cilantro, and lime.",
                AverageRating = 4.6, RatingCount = 18
            },
            new()
            {
                Id = 6, Title = "Guacamole", Category = "Mexican",
                Ingredients = "Avocados\nLime juice\nRed onion\nTomato\nCilantro\nJalapeño\nSalt",
                Steps = "1. Halve and pit the avocados.\n2. Scoop flesh into a bowl and mash with a fork.\n3. Stir in diced onion, tomato, cilantro, and jalapeño.\n4. Add lime juice and salt to taste.\n5. Serve immediately with tortilla chips.",
                AverageRating = 4.4, RatingCount = 22
            },
            new()
            {
                Id = 7, Title = "Beef Stir-Fry", Category = "Asian",
                Ingredients = "Beef sirloin\nSoy sauce\nSesame oil\nBroccoli\nBell pepper\nGarlic\nGinger\nCornstarch\nRice",
                Steps = "1. Slice beef thinly and toss with soy sauce and cornstarch.\n2. Heat sesame oil in a wok over high heat.\n3. Stir-fry beef 2 minutes, then remove.\n4. Stir-fry broccoli, bell pepper, garlic, and ginger.\n5. Return beef to the wok, toss to combine.\n6. Serve over steamed rice.",
                AverageRating = 4.2, RatingCount = 10
            },
            new()
            {
                Id = 8, Title = "Pad Thai", Category = "Asian",
                Ingredients = "Rice noodles\nShrimp or tofu\nEgg\nBean sprouts\nGreen onion\nPeanuts\nLime\nFish sauce\nTamarind paste\nSugar",
                Steps = "1. Soak rice noodles in warm water for 30 minutes.\n2. Mix tamarind paste, fish sauce, and sugar for the sauce.\n3. Stir-fry shrimp or tofu in oil until cooked.\n4. Push aside, scramble egg in the same pan.\n5. Add drained noodles and sauce, toss together.\n6. Top with bean sprouts, peanuts, green onion, and lime.",
                AverageRating = 4.5, RatingCount = 14
            },
            new()
            {
                Id = 9, Title = "Chocolate Lava Cake", Category = "Desserts",
                Ingredients = "Dark chocolate\nButter\nEggs\nSugar\nFlour\nVanilla extract",
                Steps = "1. Preheat oven to 425°F (220°C).\n2. Melt chocolate and butter together.\n3. Whisk in eggs, sugar, and vanilla.\n4. Fold in flour gently.\n5. Pour into greased ramekins.\n6. Bake 12–14 minutes until edges are firm but center is soft.\n7. Invert onto plates and serve immediately.",
                AverageRating = 4.9, RatingCount = 25
            },
            new()
            {
                Id = 10, Title = "Tiramisu", Category = "Desserts",
                Ingredients = "Ladyfinger biscuits\nEspresso\nMascarpone cheese\nEggs\nSugar\nCocoa powder\nKahlúa (optional)",
                Steps = "1. Brew espresso and let it cool.\n2. Separate eggs; whisk yolks with sugar until pale.\n3. Fold in mascarpone until smooth.\n4. Whip egg whites to stiff peaks and fold into mascarpone mixture.\n5. Dip ladyfingers briefly in espresso.\n6. Layer ladyfingers and cream in a dish, repeat.\n7. Refrigerate 4 hours. Dust with cocoa before serving.",
                AverageRating = 4.7, RatingCount = 19
