}
else
{
    <h1>@recipe.Title</h1>
    <p class="text-muted">Category: <a href="/category/@recipe.Category">@recipe.Category</a></p>

    <div class="mb-4">
        <StarRating RecipeId="@recipe.Id"
                    CurrentRating="@recipe.AverageRating"
                    RatingCount="@recipe.RatingCount" />
    </div>

    <div class="row">
        <div class="col-md-5 mb-4">
            <div class="card">
                <div class="card-header"><h5 class="mb-0">🥘 Ingredients</h5></div>
                <ul class="list-group list-group-flush">
                    @foreach (var ingredient in recipe.Ingredients.Split('\n', StringSplitOptions.RemoveEmptyEntries))
                    {
                        <li class="list-group-item">@ingredient</li>
                    }
                </ul>
            </div>
        </div>
        <div class="col-md-7 mb-4">
            <div class="card">
                <div class="card-header"><h5 class="mb-0">📋 Steps</h5></div>
                <div class="card-body">
                    @foreach (var step in recipe.Steps.Split('\n', StringSplitOptions.RemoveEmptyEntries))
                    {
                        <p>@step</p>
                    }
                </div>
            </div>
        </div>
    </div>

    <a href="/category/@recipe.Category" class="btn btn-outline-secondary">← Back to @recipe.Category</a>
}

