@page "/category/{CategoryName}"
@inject RecipeShare.Services.RecipeService RecipeService

<PageTitle>@CategoryName Recipes — RecipeShare</PageTitle>

<h1>@CategoryName Recipes</h1>

@if (recipes is null || recipes.Count == 0)
{
    <div class="alert alert-info">No recipes found in this category.</div>
}
else
{
    <div class="row">
        @foreach (var recipe in recipes)
        {
            <div class="col-md-6 mb-4">
                <div class="card h-100 shadow-sm">
                    <div class="card-body">
                        <h4 class="card-title">@recipe.Title</h4>
                        <p class="text-muted">
                            ⭐ @recipe.AverageRating / 5
                            <span class="ms-2">(@recipe.RatingCount ratings)</span>
                        </p>
                        <a href="/recipe/@recipe.Id" class="btn btn-primary">View Recipe</a>
                    </div>
                </div>
            </div>
        }
    </div>
}

<a href="/" class="btn btn-outline-secondary mt-3">← Back to Categories</a>

@code {
    [Parameter]
    public string CategoryName { get; set; } = string.Empty;

    private List<RecipeShare.Models.Recipe>? recipes;

    protected override void OnParametersSet()
    {
        recipes = RecipeService.GetByCategory(CategoryName);
    }
}

@rendermode InteractiveServer
@inject RecipeShare.Services.RecipeService RecipeService

<div class="d-inline-flex align-items-center gap-2">
    <span>
        @for (int i = 1; i <= 5; i++)
        {
            var star = i;
            <span role="button"
                  style="cursor: pointer; font-size: 1.5rem;"
                  @onclick="() => Rate(star)">
                @(star <= displayRating ? "★" : "☆")
            </span>
        }
    </span>
    <span class="text-muted">
        @if (userRating > 0)
        {
            <span>You rated @userRating/5 · </span>
        }
        @CurrentRating / 5 (@RatingCount ratings)
    </span>
</div>

@code {
    [Parameter] public int RecipeId { get; set; }
    [Parameter] public double CurrentRating { get; set; }
    [Parameter] public int RatingCount { get; set; }

    private int userRating;
    private int displayRating;

    protected override void OnParametersSet()
    {
        displayRating = (int)Math.Round(CurrentRating);
    }

    private void Rate(int stars)
    {
        userRating = stars;
        displayRating = stars;
        RecipeService.AddRating(RecipeId, stars);

        var recipe = RecipeService.GetById(RecipeId);
        if (recipe is not null)
        {
            CurrentRating = recipe.AverageRating;
            RatingCount = recipe.RatingCount;
        }
    }
}

